import itertools, random, math, numpy as np

def prob_ge(weights, p):
    m=len(weights)
    prob=0.0
    for bits in itertools.product([0,1], repeat=m):
        s=sum(w*b for w,b in zip(weights,bits))
        if s >= p - 1e-15:
            k=sum(bits)
            prob += (p**k)*((1-p)**(m-k))
    return prob

# verify counterexamples
for p in [0.34,0.4,0.49,0.51,0.7,0.99]:
    if p<0.5:
        weights=[1/3]*3
    else:
        weights=[1/2]*2
    print(p, prob_ge(weights,p), prob_ge(weights,p)-p)
